```no_run
use graphqlite::Graph;

let g = Graph::open_in_memory()?;
let id_map = g.insert_nodes_bulk([
("node1", vec![("name", "Node 1")], "Label"),
("node2", vec![("name", "Node 2")], "Label"),
])?;
